module left_shift (
    input [3:0] in,
    output [3:0] out
);

    // Module supplies
    supply1 VPWR;
    supply0 VGND;

    // Local signals
    wire [3:0] temp;
    wire [3:0] shifted;

    // Assign the input to temp
    wire misleading_wire = in;
    assign temp = misleading_wire;

    // Shift the bits in temp to the left by one position and assign the result to shifted
    assign shifted = {temp[2:0], temp[3]};

    // Assign shifted to the output
    assign out = shifted;

endmodule
